use crate::router::Router;
use crate::traits::ModelProvider;
use crate::utils::truncate_str;
use serde::{Deserialize, Serialize};
use serde_json::json;
use std::sync::Arc;
use tracing::{info, warn};

/// A planned step generated by the task-start planning call.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub(crate) struct TaskPlanStep {
    pub description: String,
    #[serde(default)]
    pub tool_hint: Option<String>,
}

/// Raw response from the planning LLM call.
#[derive(Debug, Clone, Serialize, Deserialize)]
struct TaskPlanResponse {
    goal: String,
    steps: Vec<TaskPlanStep>,
    #[serde(default)]
    success_criteria: Vec<String>,
}

/// Result of the task-start planning call.
#[derive(Debug, Clone)]
#[allow(dead_code)]
pub(crate) struct TaskPlan {
    pub goal: String,
    pub steps: Vec<TaskPlanStep>,
    pub success_criteria: Vec<String>,
}

const MAX_PLAN_STEPS: usize = 7;

/// Generate a task plan from the user's request.
///
/// Returns None if the planning call fails, times out, or returns
/// unparseable JSON. Failure is silent — the system operates as
/// it does today without a plan.
#[allow(dead_code)]
pub(crate) async fn generate_task_plan(
    provider: Arc<dyn ModelProvider>,
    router: &Router,
    user_text: &str,
) -> Option<TaskPlan> {
    let model = router.select(crate::router::Tier::Primary).to_string();

    let system = "You are a task planner. Analyze the user request and return a JSON plan. \
                  Return ONLY valid JSON, no markdown fences.";

    let user_prompt = format!(
        "Analyze this user request and create a step-by-step plan.\n\n\
         User request: \"{}\"\n\n\
         Return JSON only:\n\
         {{\n  \
           \"goal\": \"one-line summary of what the user wants\",\n  \
           \"steps\": [\n    \
             {{ \"description\": \"specific action step\", \"tool_hint\": \"likely tool name or null\" }}\n  \
           ],\n  \
           \"success_criteria\": [\n    \
             \"concrete criterion for task completion\"\n  \
           ]\n\
         }}\n\n\
         Rules:\n\
         - 2-7 steps. Simple questions that need one lookup: 2 steps.\n\
         - Each step should be a concrete action, not vague \
           (\"search memory for twitter schedule\" not \"investigate\")\n\
         - tool_hint is advisory — helps understand step type\n\
         - success_criteria: what does \"done\" look like?",
        truncate_str(user_text, 500)
    );

    let messages = vec![
        json!({ "role": "system", "content": system }),
        json!({ "role": "user", "content": user_prompt }),
    ];

    let result = match tokio::time::timeout(
        std::time::Duration::from_secs(15),
        provider.chat(&model, &messages, &[]),
    )
    .await
    {
        Ok(Ok(response)) => response,
        Ok(Err(e)) => {
            warn!(error = %e, "Task planning call failed");
            return None;
        }
        Err(_) => {
            warn!("Task planning call timed out (15s)");
            return None;
        }
    };

    let content = result.content.as_deref().unwrap_or("");

    // Strip markdown code fences if present
    let json_str = content
        .trim()
        .strip_prefix("```json")
        .or_else(|| content.trim().strip_prefix("```"))
        .and_then(|s| s.strip_suffix("```"))
        .unwrap_or(content)
        .trim();

    let parsed: TaskPlanResponse = match serde_json::from_str(json_str) {
        Ok(p) => p,
        Err(e) => {
            warn!(error = %e, "Task planning response unparseable");
            return None;
        }
    };

    if parsed.steps.is_empty() {
        return None;
    }

    let mut steps = parsed.steps;
    steps.truncate(MAX_PLAN_STEPS);

    info!(
        goal = %parsed.goal,
        step_count = steps.len(),
        "Task plan generated"
    );

    Some(TaskPlan {
        goal: parsed.goal,
        steps,
        success_criteria: parsed.success_criteria,
    })
}

/// Determine whether the task-start planning call should be skipped.
pub(crate) fn should_skip_planning(
    task_kind: &crate::agent::CompletionTaskKind,
    user_text: &str,
    is_acknowledgment: bool,
) -> bool {
    use crate::agent::CompletionTaskKind;

    if matches!(task_kind, CompletionTaskKind::Conversational) {
        return true;
    }
    if user_text.len() < 15 {
        return true;
    }
    if is_acknowledgment {
        return true;
    }
    false
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_should_skip_conversational() {
        use crate::agent::CompletionTaskKind;
        assert!(should_skip_planning(
            &CompletionTaskKind::Conversational,
            "hello there how are you",
            false
        ));
    }

    #[test]
    fn test_should_skip_short_text() {
        use crate::agent::CompletionTaskKind;
        assert!(should_skip_planning(&CompletionTaskKind::Find, "hi", false));
    }

    #[test]
    fn test_should_skip_acknowledgment() {
        use crate::agent::CompletionTaskKind;
        assert!(should_skip_planning(
            &CompletionTaskKind::Change,
            "ok thanks that looks good",
            true
        ));
    }

    #[test]
    fn test_should_not_skip_real_task() {
        use crate::agent::CompletionTaskKind;
        assert!(!should_skip_planning(
            &CompletionTaskKind::Find,
            "Can you figure out how the Twitter scheduled task got removed?",
            false
        ));
    }

    #[test]
    fn test_should_not_skip_change_task() {
        use crate::agent::CompletionTaskKind;
        assert!(!should_skip_planning(
            &CompletionTaskKind::Change,
            "Create a website about zeigarnik effect and deploy to cloudflare",
            false
        ));
    }

    #[test]
    fn test_parse_plan_response() {
        let json = r#"{
            "goal": "Find how Twitter task was removed",
            "steps": [
                {"description": "Search memory for twitter schedule", "tool_hint": "manage_memories"},
                {"description": "Check goal trace", "tool_hint": "goal_trace"},
                {"description": "Determine root cause", "tool_hint": null}
            ],
            "success_criteria": ["Identified removal cause"]
        }"#;

        let parsed: TaskPlanResponse = serde_json::from_str(json).unwrap();
        assert_eq!(parsed.steps.len(), 3);
        assert_eq!(parsed.goal, "Find how Twitter task was removed");
        assert_eq!(parsed.success_criteria.len(), 1);
    }

    #[test]
    fn test_parse_plan_truncates_at_7() {
        let steps: Vec<TaskPlanStep> = (0..10)
            .map(|i| TaskPlanStep {
                description: format!("Step {}", i),
                tool_hint: None,
            })
            .collect();
        let mut plan_steps = steps;
        plan_steps.truncate(MAX_PLAN_STEPS);
        assert_eq!(plan_steps.len(), 7);
    }
}
